virtualhostnodes.virtualHostInitialConfiguration:
{
  "type": "Memory",
  "name": "localhost",
  "modelVersion": "7.0",
  "exchanges": [
    {
      "name": "headerEx",
      "type": "headers",
      "durable": true,
      "durableBindings": [
        {
          "arguments": {
            "x-filter-jms-selector": "how = 'fisk' and what = 'torsk'"
          },
          "bindingKey": "headerFiskTorsk",
          "destination": "qFiskTorsk"
        },
        {
          "arguments": {
            "x-filter-jms-selector": "how = 'fisk' and what = 'flyndre'"
          },
          "bindingKey": "headerFiskFlyndre",
          "destination": "qFiskFlyndre"
        },
        {
          "arguments": {
            "x-filter-jms-selector": "how = 'fisk'"
          },
          "bindingKey": "headerFisk",
          "destination": "qFisk"
        }
      ]
    },
    {
      "name": "topicEx",
      "type": "topic",
      "durable": true,
      "durableBindings": [
        {
          "bindingKey": "fisk.torsk",
          "destination": "qFiskTorsk"
        },
        {
          "bindingKey": "fisk.flyndre",
          "destination": "qFiskFlyndre"
        },
        {
          "bindingKey": "fisk.#",
          "destination": "qFisk"
        }
      ],
      "alternateBinding" : {
        "destination" : "headerEx"
      }
    }
  ],
  "queues": [
    {
      "name": "qFiskTorsk",
      "type": "standard",
      "durable": true,
      "holdOnPublishEnabled": false
    },
    {
      "name": "qFiskFlyndre",
      "type": "standard",
      "durable": true,
      "holdOnPublishEnabled": false
    },
    {
      "name": "qFisk",
      "type": "standard",
      "durable": true,
      "holdOnPublishEnabled": false
    }
  ]
}
